"use client";

import Link from "next/link";
import type { ReactNode } from "react";
import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { ActivitySquare, ArchiveRestore, ShieldAlert, TestTube2 } from "lucide-react";
import { requestJson } from "@/features/workforce/helpers";
import { EmptyState } from "@/components/empty-state";
import { ErrorPanel } from "@/components/error-panel";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { getOperationsReadiness } from "@/lib/api";
import type { CockpitSectionState, OperationsReadinessSnapshot } from "@/lib/contracts";
import { compactText, formatRelativeTime, formatTimestamp } from "@/lib/format";
import { queryKeys } from "@/lib/query-client";

function compactLabel(value: string) {
  return value.replace(/_/g, " ");
}

function statusVariant(status: string) {
  if (status === "configured" || status === "planned drill" || status === "reviewed_repo_truth") {
    return "secondary" as const;
  }
  if (status === "degraded" || status === "blocked" || status === "drifted") {
    return "destructive" as const;
  }
  if (status === "live_partial" || status === "candidate_truth") {
    return "secondary" as const;
  }
  return "outline" as const;
}

function isParityBlocker(status: string) {
  return !["live", "configured", "reviewed_repo_truth", "deployment_truth"].includes(status);
}

function sourceStateVariant(state: string) {
  if (state === "live" || state === "clear") {
    return "outline" as const;
  }
  if (state === "degraded" || state === "missing" || state === "blocked") {
    return "destructive" as const;
  }
  return "secondary" as const;
}

function renderSourceState(sourceState?: CockpitSectionState) {
  if (!sourceState) {
    return <Badge variant="secondary">unknown</Badge>;
  }

  return (
    <div className="flex flex-col items-end gap-1 text-right">
      <Badge variant={sourceStateVariant(sourceState.state)}>{compactLabel(sourceState.state)}</Badge>
      <div className="space-y-0.5 text-[11px] text-muted-foreground">
        {sourceState.last_updated_at ? (
          <p data-volatile="true">updated {formatRelativeTime(sourceState.last_updated_at)}</p>
        ) : null}
        {sourceState.stale_after ? (
          <p data-volatile="true">stale after {formatTimestamp(sourceState.stale_after)}</p>
        ) : null}
        {sourceState.snapshot_version ? (
          <p>version {compactText(sourceState.snapshot_version, 18)}</p>
        ) : null}
      </div>
    </div>
  );
}

function renderParityBlockerContent(blocker: {
  label: string;
  status: string;
  detail: string;
  owner_action?: string;
  next_action?: string;
  validation?: string;
  next_step?: string;
  deep_link?: string;
}) {
  const blockerAction = blocker.owner_action ?? blocker.next_action;
  return (
    <>
      <div className="flex items-center justify-between gap-3">
        <p className="text-sm font-medium">{blocker.label}</p>
        <Badge variant={statusVariant(blocker.status)}>{compactLabel(blocker.status)}</Badge>
      </div>
      <p className="mt-1 text-xs text-muted-foreground">{blocker.detail}</p>
      {blockerAction ? (
        blocker.deep_link ? (
          <Link
            href={blocker.deep_link}
            className="mt-2 inline-flex text-xs text-primary underline underline-offset-4"
          >
            owner action: {blockerAction}
          </Link>
        ) : (
          <p className="mt-2 text-xs text-muted-foreground">owner action: {blockerAction}</p>
        )
      ) : null}
      {blocker.validation ? (
        <p className="mt-1 text-xs text-muted-foreground">validation: {blocker.validation}</p>
      ) : null}
      {blocker.next_step ? (
        <p className="mt-1 text-xs text-muted-foreground">next step: {blocker.next_step}</p>
      ) : null}
    </>
  );
}

export function OperationsReadinessCard({
  compact = false,
  snapshot: providedSnapshot,
  sourceState,
}: {
  compact?: boolean;
  snapshot?: OperationsReadinessSnapshot;
  sourceState?: CockpitSectionState;
}) {
  const [busy, setBusy] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);
  const queryClient = useQueryClient();
  const readinessQuery = useQuery({
    queryKey: queryKeys.operationsReadiness,
    queryFn: getOperationsReadiness,
    enabled: !providedSnapshot,
    refetchInterval: 60_000,
    refetchIntervalInBackground: false,
  });

  async function runOperatorTests() {
    setBusy(true);
    setFeedback(null);
    try {
      await requestJson("/api/governor/operator-tests", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ actor: "dashboard-operator" }),
      });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.operationsReadiness }),
        queryClient.invalidateQueries({ queryKey: queryKeys.cockpit }),
      ]);
    } catch (error) {
      setFeedback(error instanceof Error ? error.message : "Failed to run synthetic operator tests.");
    } finally {
      setBusy(false);
    }
  }

  if (!providedSnapshot && readinessQuery.isError && !readinessQuery.data) {
    return (
      <ErrorPanel
        title="Operations readiness"
        description={
          readinessQuery.error instanceof Error
            ? readinessQuery.error.message
            : "Failed to load operations-readiness posture."
        }
      />
    );
  }

  const snapshot = providedSnapshot ?? readinessQuery.data;
  if (!snapshot) {
    return (
      <EmptyState
        title="No operations-readiness snapshot yet"
        description="Restore posture, release ritual, and operator-test evidence have not been surfaced yet."
      />
    );
  }

  const runbooks = compact ? snapshot.runbooks.items.slice(0, 3) : snapshot.runbooks.items;
  const stores = compact
    ? snapshot.backup_restore.critical_stores.slice(0, 3)
    : snapshot.backup_restore.critical_stores;
  const flows = compact
    ? snapshot.synthetic_operator_tests.flows.slice(0, 3)
    : snapshot.synthetic_operator_tests.flows;
  const parityChecks = compact
    ? snapshot.environment_parity.checks.slice(0, 4)
    : snapshot.environment_parity.checks;
  const parityHosts = compact
    ? snapshot.environment_parity.authoritative_hosts.slice(0, 4)
    : snapshot.environment_parity.authoritative_hosts;
  const parityIssues = compact
    ? snapshot.environment_parity.issues.slice(0, 2)
    : snapshot.environment_parity.issues.slice(0, 4);
  const dirtyPaths = compact
    ? snapshot.trunk_release.sample_dirty_paths.slice(0, 2)
    : snapshot.trunk_release.sample_dirty_paths.slice(0, 4);
  const truthGateReasons = compact
    ? snapshot.operator_truth_gate.blocking_reasons.slice(0, 2)
    : snapshot.operator_truth_gate.blocking_reasons.slice(0, 4);
  const parityBlockers = (
    snapshot.environment_parity.blockers.length > 0
      ? snapshot.environment_parity.blockers
      : snapshot.environment_parity.checks
          .filter((check) => check.blocking ?? isParityBlocker(check.status))
          .map((check) => ({
            id: check.id,
            check_id: check.id,
            label: check.label,
            status: check.status,
            detail: check.detail,
            owner_action: check.next_action,
            validation: undefined,
            next_step: undefined,
            deep_link: check.deep_link,
          }))
  ).slice(0, compact ? 2 : 4);
  const parityBlockerIds = new Set(parityBlockers.map((blocker) => blocker.id));
  const truthGateBlockers = (snapshot.operator_truth_gate.blocking_items ?? [])
    .filter((blocker) => !parityBlockerIds.has(blocker.id))
    .slice(0, compact ? 2 : 4);
  const dependencyPackets = compact
    ? snapshot.dependency_packets.packets.slice(0, 3)
    : snapshot.dependency_packets.packets;
  const verifiedStores =
    snapshot.backup_restore.verified_store_count ??
    snapshot.backup_restore.critical_stores.filter((store) => store.verified).length;
  const totalStores =
    snapshot.backup_restore.store_count ?? snapshot.backup_restore.critical_stores.length;
  const providerStateSummary = Object.entries(snapshot.economic_governance.provider_state_counts ?? {})
    .filter(([, count]) => count > 0)
    .slice(0, compact ? 2 : 4)
    .map(([state, count]) => `${compactLabel(state)} ${count}`)
    .join(" | ");
  const handoffStatusSummary = Object.entries(snapshot.economic_governance.handoff_status_counts ?? {})
    .filter(([, count]) => count > 0)
    .slice(0, compact ? 2 : 4)
    .map(([state, count]) => `${compactLabel(state)} ${count}`)
    .join(" | ");
  const economicDegradedReasons = compact
    ? (snapshot.economic_governance.degraded_reasons ?? []).slice(0, 1)
    : (snapshot.economic_governance.degraded_reasons ?? []).slice(0, 3);

  return (
    <Card className="surface-panel" id="operations-readiness">
      <CardHeader>
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="space-y-1">
            <CardTitle className="flex items-center gap-2 text-lg">
              <ShieldAlert className="h-5 w-5 text-primary" />
              Operations readiness
            </CardTitle>
            <CardDescription>
              Restore posture, release ladder, lifecycle governance, and synthetic operator-test evidence.
            </CardDescription>
          </div>
          <div className="flex flex-col items-end gap-2">
            {renderSourceState(sourceState)}
            <Button size="sm" variant="outline" onClick={() => void runOperatorTests()} disabled={busy}>
              {busy ? "Running..." : "Run tests"}
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {feedback ? (
          <div className="rounded-xl border border-red-500/30 bg-red-500/10 px-3 py-2 text-sm text-red-100">
            {feedback}
          </div>
        ) : null}

        <div className="grid gap-3 sm:grid-cols-4">
          <Metric
            icon={<ArchiveRestore className="h-4 w-4 text-primary" />}
            label="Restore"
            value={`${verifiedStores}/${totalStores} verified`}
            detail={
              snapshot.backup_restore.last_drill_at
                ? `${compactLabel(snapshot.backup_restore.status)} | ${formatRelativeTime(
                    snapshot.backup_restore.last_drill_at
                  )}`
                : compactLabel(snapshot.backup_restore.status)
            }
          />
          <Metric
            icon={<ActivitySquare className="h-4 w-4 text-primary" />}
            label="Release ladder"
            value={`${snapshot.release_ritual.tiers.length} tiers`}
            detail={
              snapshot.release_ritual.last_rehearsal_at
                ? `${compactLabel(snapshot.release_ritual.status)} | ${formatRelativeTime(
                    snapshot.release_ritual.last_rehearsal_at
                  )}`
                : compactLabel(snapshot.release_ritual.status)
            }
          />
          <Metric
            icon={<TestTube2 className="h-4 w-4 text-primary" />}
            label="Synthetic flows"
            value={`${snapshot.synthetic_operator_tests.flows.length}`}
            detail={
              snapshot.synthetic_operator_tests.last_run_at
                ? `${compactLabel(snapshot.synthetic_operator_tests.status)} · ${formatRelativeTime(
                    snapshot.synthetic_operator_tests.last_run_at
                  )}`
                : compactLabel(snapshot.synthetic_operator_tests.status)
            }
          />
          <Metric
            icon={<ShieldAlert className="h-4 w-4 text-primary" />}
            label="Lifecycle"
            value={`${snapshot.data_lifecycle.classes.length} classes`}
            detail={`${snapshot.deprecation_retirement.asset_classes.length} retirement classes`}
          />
        </div>

        <div className="grid gap-3 lg:grid-cols-[1.05fr_0.95fr]">
          <div className="space-y-3">
            <SectionTitle title="Runbooks" />
            <div className="space-y-2">
              {runbooks.map((runbook) => (
                <div
                  key={runbook.id}
                className="surface-metric rounded-xl border px-3 py-3"
                >
                  <div className="flex items-center justify-between gap-3">
                    <p className="font-medium">{runbook.label}</p>
                    <div className="flex flex-wrap items-center gap-2">
                      {runbook.support_status ? (
                        <Badge variant={statusVariant(runbook.support_status)}>
                          {compactLabel(runbook.support_status)}
                        </Badge>
                      ) : null}
                      <Badge variant="outline">{runbook.cadence ?? "as-needed"}</Badge>
                    </div>
                  </div>
                  {runbook.description ? (
                    <p className="mt-1 text-sm text-muted-foreground">{runbook.description}</p>
                  ) : null}
                  {runbook.related_surface ? (
                    <p className="mt-2 text-xs text-muted-foreground">
                      cockpit surface {runbook.related_surface}
                    </p>
                  ) : null}
                  {runbook.evidence_flow_ids && runbook.evidence_flow_ids.length > 0 ? (
                    <div className="mt-2 flex flex-wrap gap-2">
                      {runbook.evidence_flow_ids.slice(0, compact ? 2 : 3).map((flowId) => (
                        <Badge key={flowId} variant="secondary">
                          {compactLabel(flowId)}
                        </Badge>
                      ))}
                    </div>
                  ) : null}
                </div>
              ))}
            </div>

            <SectionTitle title="Synthetic operator tests" />
            <div className="space-y-2">
              {flows.map((flow) => (
                <div
                  key={flow.id}
                className="surface-metric rounded-xl border px-3 py-3"
                >
                  <div className="flex items-center justify-between gap-3">
                    <p className="font-medium">{flow.title}</p>
                    <Badge variant={statusVariant(flow.status)}>{compactLabel(flow.status)}</Badge>
                  </div>
                  {flow.description ? (
                    <p className="mt-1 text-sm text-muted-foreground">{flow.description}</p>
                  ) : null}
                  <div className="mt-2 flex flex-wrap gap-2 text-xs text-muted-foreground">
                    <span>
                      checks {flow.checks_passed ?? 0}/{flow.checks_total ?? 0}
                    </span>
                    {flow.last_outcome ? <span>outcome {compactLabel(flow.last_outcome)}</span> : null}
                    {flow.last_run_at ? (
                      <span data-volatile="true">updated {formatRelativeTime(flow.last_run_at)}</span>
                    ) : (
                      <span>not run yet</span>
                    )}
                  </div>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {flow.evidence.map((item) => (
                      <Badge key={item} variant="secondary">
                        {item}
                      </Badge>
                    ))}
                  </div>
                  {flow.notes && flow.notes.length > 0 ? (
                    <div className="mt-2 space-y-1 text-xs text-muted-foreground">
                      {flow.notes.slice(0, compact ? 1 : 2).map((note) => (
                        <p key={note}>{note}</p>
                      ))}
                    </div>
                  ) : null}
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <SectionTitle title="Backup and release posture" />
            <div className="space-y-2">
              {stores.map((store) => (
                <div
                  key={store.id}
                className="surface-metric rounded-xl border px-3 py-3"
                >
                  <div className="flex items-center justify-between gap-3">
                    <p className="font-medium">{store.label ?? compactLabel(store.id)}</p>
                    <Badge variant={statusVariant(store.drill_status ?? "configured")}>
                      {compactLabel(store.drill_status ?? "configured")}
                    </Badge>
                  </div>
                  <p className="mt-1 text-xs text-muted-foreground">
                    order {store.restore_order ?? "--"}
                    {store.cadence ? ` | ${store.cadence}` : ""}
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2 text-xs text-muted-foreground">
                    <span>{store.verified ? "verified" : "awaiting live proof"}</span>
                    {store.last_drill_at ? (
                      <span data-volatile="true">updated {formatRelativeTime(store.last_drill_at)}</span>
                    ) : null}
                    {store.last_outcome ? <span>outcome {compactLabel(store.last_outcome)}</span> : null}
                  </div>
                  {store.probe_summary ? (
                    <p className="mt-2 text-xs text-muted-foreground">{store.probe_summary}</p>
                  ) : null}
                </div>
              ))}
            </div>

          <div className="surface-metric rounded-xl border px-3 py-3">
              <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">
                Release ritual
              </p>
              <div className="mt-2 grid gap-2 text-sm text-muted-foreground">
                <span>status {compactLabel(snapshot.release_ritual.status)}</span>
                <span>
                  rehearsal{" "}
                  {compactLabel(snapshot.release_ritual.rehearsal_status ?? "configured")}
                  {snapshot.release_ritual.last_outcome
                    ? ` | outcome ${compactLabel(snapshot.release_ritual.last_outcome)}`
                    : ""}
                </span>
                {snapshot.release_ritual.last_rehearsal_at ? (
                  <span data-volatile="true">
                    last rehearsal {formatRelativeTime(snapshot.release_ritual.last_rehearsal_at)}
                  </span>
                ) : null}
                <span>
                  active promotions {snapshot.release_ritual.active_promotion_count ?? 0}
                </span>
              </div>
              <div className="mt-2 flex flex-wrap gap-2">
                {snapshot.release_ritual.tiers.map((tier) => (
                  <Badge key={tier} variant="secondary">
                    {compactLabel(tier)}
                  </Badge>
                ))}
              </div>
              <div className="mt-3 flex flex-wrap gap-2 text-xs text-muted-foreground">
                {snapshot.release_ritual.ritual.map((step) => (
                  <span key={step} className="rounded-full border border-border/60 px-2 py-1">
                    {compactLabel(step)}
                  </span>
                ))}
              </div>
            </div>

          <div className="space-y-2">
              <SectionTitle title="Environment parity and trunk truth" />
              <div
                className="surface-metric rounded-xl border px-3 py-3"
                data-testid="operations-truth-gate"
                id="operations-truth-gate"
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="font-medium">Operator truth gate</p>
                  <Badge variant={statusVariant(snapshot.operator_truth_gate.status)}>
                    {compactLabel(snapshot.operator_truth_gate.status)}
                  </Badge>
                </div>
                <div className="mt-2 grid gap-2 text-sm text-muted-foreground">
                  <span>
                    compare {compactLabel(snapshot.operator_truth_gate.compare_status)}
                    {" | "}
                    ahead {snapshot.operator_truth_gate.ahead_by ?? "--"}
                    {" | "}
                    behind {snapshot.operator_truth_gate.behind_by ?? "--"}
                  </span>
                  <span>
                    dirty paths {snapshot.operator_truth_gate.dirty_path_count}
                    {" | "}
                    WSL {compactLabel(snapshot.operator_truth_gate.wsl_status)}
                    {" | "}
                    DEV {compactLabel(snapshot.operator_truth_gate.dev_status)}
                  </span>
                  <span>
                    live {compactLabel(snapshot.operator_truth_gate.live_status)}
                    {" | "}
                    catalog auth {snapshot.operator_truth_gate.catalog_auth_checked ? "checked" : "pending"}
                  </span>
                  {snapshot.operator_truth_gate.last_verified_at ? (
                    <span data-volatile="true">
                      last verified {formatRelativeTime(snapshot.operator_truth_gate.last_verified_at)}
                    </span>
                  ) : null}
                </div>
                {truthGateReasons.length > 0 ? (
                  <div className="mt-3 space-y-1 text-xs text-muted-foreground">
                    {truthGateReasons.map((reason) => (
                      <p key={reason}>{reason}</p>
                    ))}
                  </div>
                ) : (
                  <p className="mt-3 text-xs text-muted-foreground">
                    Repo, operator host, and live runtime truth are converged enough to treat the current posture as canonical.
                  </p>
                )}
                {truthGateBlockers.length > 0 ? (
                  <div className="mt-3 space-y-2">
                    {truthGateBlockers.map((blocker) => (
                      <div key={blocker.id} className="rounded-lg border border-border/60 px-3 py-2">
                        {renderParityBlockerContent(blocker)}
                      </div>
                    ))}
                  </div>
                ) : null}
              </div>

              <div
                className="surface-metric rounded-xl border px-3 py-3"
                data-testid="operations-environment-parity"
                id="operations-environment-parity"
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="font-medium">Environment parity</p>
                  <Badge variant={statusVariant(snapshot.environment_parity.status)}>
                    {compactLabel(snapshot.environment_parity.status)}
                  </Badge>
                </div>
                <div className="mt-2 grid gap-2 text-sm text-muted-foreground">
                  <span>adapter host {snapshot.environment_parity.adapter_host}</span>
                  <span>
                    parity issues {snapshot.environment_parity.issue_count}
                    {" | "}
                    checks {snapshot.environment_parity.checks.length}
                  </span>
                  {snapshot.environment_parity.last_verified_at ? (
                    <span data-volatile="true">
                      last verified {formatRelativeTime(snapshot.environment_parity.last_verified_at)}
                    </span>
                  ) : null}
                </div>
                <div className="mt-3 flex flex-wrap gap-2">
                  {parityHosts.map((host) => (
                    <Badge key={host.id} variant="secondary">
                      {host.label} {"|"} {compactLabel(host.status)}
                    </Badge>
                  ))}
                </div>
                {parityBlockers.length > 0 ? (
                  <div className="mt-3 space-y-2">
                    {parityBlockers.map((blocker) => (
                      <div key={blocker.id} className="rounded-lg border border-border/60 px-3 py-2">
                        {renderParityBlockerContent(blocker)}
                      </div>
                    ))}
                  </div>
                ) : null}
                <div className="mt-3 space-y-2">
                  {parityChecks.map((check) => (
                    <div key={check.id} className="rounded-lg border border-border/60 px-3 py-2">
                      <div className="flex items-center justify-between gap-3">
                        <p className="text-sm font-medium">{check.label}</p>
                        <Badge variant={statusVariant(check.status)}>{compactLabel(check.status)}</Badge>
                      </div>
                      <p className="mt-1 text-xs text-muted-foreground">{check.detail}</p>
                      {check.next_action ? (
                        check.deep_link ? (
                          <Link
                            href={check.deep_link}
                            className="mt-2 inline-flex text-xs text-primary underline underline-offset-4"
                          >
                            next: {check.next_action}
                          </Link>
                        ) : (
                          <p className="mt-2 text-xs text-muted-foreground">next: {check.next_action}</p>
                        )
                      ) : null}
                    </div>
                  ))}
                </div>
                {parityIssues.length > 0 ? (
                  <div className="mt-3 space-y-1 text-xs text-muted-foreground">
                    {parityIssues.map((issue) => (
                      <p key={issue}>{issue}</p>
                    ))}
                  </div>
                ) : null}
                {snapshot.environment_parity.next_actions.length > 0 ? (
                  <div className="mt-3 flex flex-wrap gap-2">
                    {snapshot.environment_parity.next_actions
                      .slice(0, compact ? 2 : 3)
                      .map((action) => (
                        <Badge key={action} variant="secondary">
                          {action}
                        </Badge>
                      ))}
                  </div>
                ) : null}
              </div>

              <div
                className="surface-metric rounded-xl border px-3 py-3"
                data-testid="operations-trunk-release"
                id="operations-trunk-release"
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="font-medium">Trunk release truth</p>
                  <Badge variant={statusVariant(snapshot.trunk_release.status)}>
                    {compactLabel(snapshot.trunk_release.status)}
                  </Badge>
                </div>
                <ul className="mt-2 space-y-1 text-sm text-muted-foreground">
                  <li>
                    local branch: {snapshot.trunk_release.local_branch}
                    {" | "}
                    canonical branch: {snapshot.trunk_release.canonical_branch}
                  </li>
                  <li>
                    ahead by: {snapshot.trunk_release.ahead_by ?? "--"}
                    {" | "}
                    behind by: {snapshot.trunk_release.behind_by ?? "--"}
                  </li>
                  <li>
                    dirty paths: {snapshot.trunk_release.dirty_path_count}
                    {" | "}
                    untracked: {snapshot.trunk_release.untracked_count}
                  </li>
                  <li>latest tag: {snapshot.trunk_release.latest_tag ?? "none"}</li>
                  {snapshot.trunk_release.last_verified_at ? (
                    <li data-volatile="true">
                      last verified {formatRelativeTime(snapshot.trunk_release.last_verified_at)}
                    </li>
                  ) : null}
                </ul>
                <p className="mt-3 text-xs text-muted-foreground">
                  {snapshot.trunk_release.release_rule}
                </p>
                <div className="mt-3 space-y-1 text-xs text-muted-foreground">
                  {snapshot.trunk_release.shipped_definition
                    .slice(0, compact ? 2 : 4)
                    .map((item) => (
                      <p key={item}>{item}</p>
                    ))}
                </div>
                <div className="mt-3 flex flex-wrap gap-2">
                  {dirtyPaths.map((path) => (
                    <Badge key={path} variant="secondary">
                      {path}
                    </Badge>
                  ))}
                </div>
              </div>

              <div
                className="surface-metric rounded-xl border px-3 py-3"
                data-testid="operations-dependency-packets"
                id="operations-dependency-packets"
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="font-medium">Dependency packets</p>
                  <Badge variant={statusVariant(snapshot.dependency_packets.status)}>
                    {compactLabel(snapshot.dependency_packets.status)}
                  </Badge>
                </div>
                <div className="mt-2 grid gap-2 text-sm text-muted-foreground">
                  <span>
                    blocked {snapshot.dependency_packets.blocked_count}
                    {" | "}
                    credentials {snapshot.dependency_packets.credential_count}
                    {" | "}
                    operator actions {snapshot.dependency_packets.operator_action_count}
                  </span>
                  <span>
                    decisions {snapshot.dependency_packets.decision_count}
                    {" | "}
                    source {snapshot.dependency_packets.source_path}
                  </span>
                  {snapshot.dependency_packets.last_verified_at ? (
                    <span data-volatile="true">
                      last verified {formatRelativeTime(snapshot.dependency_packets.last_verified_at)}
                    </span>
                  ) : null}
                </div>
                {snapshot.dependency_packets.issues.length > 0 ? (
                  <div className="mt-3 space-y-1 text-xs text-muted-foreground">
                    {snapshot.dependency_packets.issues.map((issue) => (
                      <p key={issue}>{issue}</p>
                    ))}
                  </div>
                ) : null}
                {dependencyPackets.length > 0 ? (
                  <div className="mt-3 space-y-2">
                    {dependencyPackets.map((packet) => (
                      <div key={packet.id} className="rounded-lg border border-border/60 px-3 py-2">
                        <div className="flex flex-wrap items-center justify-between gap-3">
                          <p className="text-sm font-medium">{packet.dependency}</p>
                          <div className="flex flex-wrap gap-2">
                            <Badge variant={statusVariant(packet.status)}>{compactLabel(packet.status)}</Badge>
                            <Badge variant="secondary">{compactLabel(packet.kind)}</Badge>
                          </div>
                        </div>
                        <p className="mt-2 text-xs text-muted-foreground">owner: {packet.owner}</p>
                        <p className="mt-2 text-xs text-muted-foreground">
                          owner action: {packet.owner_action}
                        </p>
                        <p className="mt-1 text-xs text-muted-foreground">
                          target service: {packet.target_service}
                        </p>
                        <p className="mt-1 text-xs text-muted-foreground">
                          validation: {packet.validation}
                        </p>
                        <p className="mt-1 text-xs text-muted-foreground">
                          first step: {packet.first_step_after_unblock}
                        </p>
                        {packet.owner_docs.length > 0 ? (
                          <div className="mt-2 flex flex-wrap gap-2">
                            {packet.owner_docs.slice(0, compact ? 2 : 4).map((doc) => (
                              <Badge key={`${packet.id}:${doc}`} variant="outline">
                                {doc}
                              </Badge>
                            ))}
                          </div>
                        ) : null}
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="mt-3 text-xs text-muted-foreground">
                    No Shaun-gated dependency packets are currently registered.
                  </p>
                )}
              </div>
            </div>

          <div className="surface-metric rounded-xl border px-3 py-3">
              <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">
                Economic and lifecycle posture
              </p>
              <ul className="mt-2 space-y-1 text-sm text-muted-foreground">
                <li>economic status: {compactLabel(snapshot.economic_governance.status)}</li>
                <li>
                  reserve lanes: {snapshot.economic_governance.premium_reserve_lanes.join(", ")}
                </li>
                <li>
                  live providers: {snapshot.economic_governance.provider_count ?? 0}
                  {" | "}
                  recent leases: {snapshot.economic_governance.recent_lease_count ?? 0}
                  {" | "}
                  constrained: {snapshot.economic_governance.constrained_count ?? 0}
                </li>
                <li>
                  direct ready: {snapshot.economic_governance.direct_execution_ready_count ?? 0}
                  {" | "}
                  handoff ready: {snapshot.economic_governance.governed_handoff_ready_count ?? 0}
                  {" | "}
                  adapters live: {snapshot.economic_governance.adapter_ready_count ?? 0}
                </li>
                <li>
                  recent handoffs: {snapshot.economic_governance.recent_handoff_count ?? 0}
                  {" | "}
                  recent executions: {snapshot.economic_governance.recent_execution_count ?? 0}
                  {" | "}
                  recent events: {snapshot.economic_governance.recent_event_count ?? 0}
                </li>
                {providerStateSummary ? <li>provider states: {providerStateSummary}</li> : null}
                {handoffStatusSummary ? <li>handoff states: {handoffStatusSummary}</li> : null}
                <li>
                  approval-required lanes:{" "}
                  {snapshot.economic_governance.approval_required_lanes.join(", ")}
                </li>
                <li>
                  downgrade order: {snapshot.economic_governance.downgrade_order.join(" -> ")}
                </li>
                {snapshot.economic_governance.last_verified_at ? (
                  <li data-volatile="true">
                    last verified {formatRelativeTime(snapshot.economic_governance.last_verified_at)}
                  </li>
                ) : null}
                {economicDegradedReasons.map((reason) => (
                  <li key={reason}>provider drift: {reason}</li>
                ))}
                <li>lifecycle status: {compactLabel(snapshot.data_lifecycle.status)}</li>
                <li>
                  sovereign-only lifecycle classes:{" "}
                  {snapshot.data_lifecycle.classes.filter((item) => item.sovereign_only).length}
                </li>
                <li>
                  runtime runs: {snapshot.data_lifecycle.run_count ?? 0}
                  {" | "}
                  eval artifacts: {snapshot.data_lifecycle.eval_artifact_count ?? 0}
                </li>
                {snapshot.data_lifecycle.last_verified_at ? (
                  <li data-volatile="true">
                    lifecycle verified {formatRelativeTime(snapshot.data_lifecycle.last_verified_at)}
                  </li>
                ) : null}
                <li>
                  retirement status: {compactLabel(snapshot.deprecation_retirement.status)}
                </li>
                <li>
                  retirement candidates: {snapshot.deprecation_retirement.active_retirement_count ?? 0}
                  {" | "}
                  rehearsed records: {snapshot.deprecation_retirement.recent_retirement_count ?? 0}
                </li>
                {snapshot.deprecation_retirement.last_rehearsal_at ? (
                  <li data-volatile="true">
                    retirement rehearsal{" "}
                    {formatRelativeTime(snapshot.deprecation_retirement.last_rehearsal_at)}
                  </li>
                ) : null}
                <li>tool-permission status: {compactLabel(snapshot.tool_permissions.status)}</li>
                <li>default tool mode: {compactLabel(snapshot.tool_permissions.default_mode)}</li>
                <li>
                  enforced subjects: {snapshot.tool_permissions.enforced_subject_count ?? 0}
                  {" | "}
                  denied checks: {snapshot.tool_permissions.denied_action_count ?? 0}
                </li>
                {snapshot.tool_permissions.last_verified_at ? (
                  <li data-volatile="true">
                    tool permissions verified{" "}
                    {formatRelativeTime(snapshot.tool_permissions.last_verified_at)}
                  </li>
                ) : null}
              </ul>
              <div className="mt-3 flex flex-wrap gap-2">
                {snapshot.deprecation_retirement.asset_classes.map((assetClass) => (
                  <Badge key={`retirement-${assetClass}`} variant="secondary">
                    retire {compactLabel(assetClass)}
                  </Badge>
                ))}
                {snapshot.tool_permissions.subjects.map((subject) => (
                  <Badge key={subject.subject} variant="secondary">
                    {(subject.label ?? compactLabel(subject.subject)).toLowerCase()}{" "}
                    {"|"} {compactLabel(subject.mode ?? snapshot.tool_permissions.default_mode)}
                  </Badge>
                ))}
              </div>
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function SectionTitle({ title }: { title: string }) {
  return (
    <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">{title}</p>
  );
}

function Metric({
  icon,
  label,
  value,
  detail,
}: {
  icon: ReactNode;
  label: string;
  value: string;
  detail: string;
}) {
  return (
          <div className="surface-metric rounded-xl border px-3 py-3">
      <div className="flex items-center gap-2 text-muted-foreground">{icon}</div>
      <p className="mt-2 text-[11px] uppercase tracking-[0.18em] text-muted-foreground">{label}</p>
      <p className="mt-1 text-sm font-semibold">{value}</p>
      <p className="mt-1 text-xs text-muted-foreground">{detail}</p>
    </div>
  );
}
