function formatLabel(value: string | null | undefined) {
  return String(value ?? "unknown").replace(/_/g, " ");
}

function badgeVariantForState(state: string) {
  if (state === "live" || state === "clear") {
    return "outline" as const;
  }
  if (state === "degraded" || state === "missing" || state === "blocked") {
    return "destructive" as const;
  }
  return "secondary" as const;
}

function badgeVariantForSeverity(severity: string) {
  if (severity === "error") {
    return "destructive" as const;
  }
  if (severity === "warning") {
    return "secondary" as const;
  }
  return "outline" as const;
}

function toneForStat(count: number) {
  return count > 0 ? "warning" : "success";
}

function renderSourceBadge(snapshot: CockpitSnapshot, key: keyof CockpitSnapshot["source_states"]) {
  const source = snapshot.source_states[key];
  if (!source) {
    return (
      <div className="flex flex-col items-end gap-1 text-right">
        <Badge variant="secondary">unknown</Badge>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-end gap-1 text-right">
      <Badge variant={badgeVariantForState(source.state)}>{formatLabel(source.state)}</Badge>
      <div className="space-y-0.5 text-[11px] text-muted-foreground">
        {source.last_updated_at ? (
          <p data-volatile="true">updated {formatRelativeTime(source.last_updated_at)}</p>
        ) : null}
        {source.stale_after ? (
          <p data-volatile="true">stale after {formatTimestamp(source.stale_after)}</p>
        ) : null}
        {source.snapshot_version ? <p>version {compactText(source.snapshot_version, 18)}</p> : null}
      </div>
    </div>
  );
}

function getProviderActionDetail(provider: CockpitSnapshot["provider_plane"]["provider_posture"][number]) {
  return (
    provider.next_action_detail ??
    provider.blocked_direct_detail ??
    (provider.auth_required && !provider.auth_ready ? provider.auth_detail : undefined) ??
    provider.bridge_detail ??
    provider.recent_execution_detail ??
    null
  );
}

function getProviderBlockedReason(provider: CockpitSnapshot["provider_plane"]["provider_posture"][number]) {
  return (
    provider.blocked_direct_reason ??
    (provider.auth_required && !provider.auth_ready ? "auth_missing" : undefined) ??
    (provider.direct_execution_ready ? null : provider.bridge_status ?? null)
  );
}

function getProviderOperability(provider: CockpitSnapshot["provider_plane"]["provider_posture"][number]) {
  if (provider.direct_execution_ready) {
    return "Direct execution is ready on this lane.";
  }
  if (provider.governed_handoff_ready) {
    return "Governed handoff remains available while the direct path is blocked.";
  }
  return "This lane is currently blocked with no governed fallback.";
}

function getProviderValidation(provider: CockpitSnapshot["provider_plane"]["provider_posture"][number]) {
  const blockedReason = getProviderBlockedReason(provider);
  if (!blockedReason) {
    return null;
  }
  if (blockedReason === "auth_missing") {
    if (provider.provider === "openai_codex") {
      return "Confirm Codex login is configured on DEV, then retry direct execution from subscription control.";
    }
    if (provider.provider === "google_gemini") {
      return "Confirm Gemini auth is present on DEV, then retry the direct audit lane from subscription control.";
    }
    return "Confirm the provider auth path is configured on DEV, then retry direct execution from subscription control.";
  }
  if (blockedReason === "ccr_config_missing") {
    return "Re-run environment parity and confirm CCR config is present on DEV before retrying direct execution.";
  }
  if (blockedReason === "path_parity_partial") {
    return "Re-run environment parity and confirm the noninteractive DEV PATH is normalized before retrying direct execution.";
  }
  return provider.bridge_detail ?? null;
}

function getProviderNextStep(provider: CockpitSnapshot["provider_plane"]["provider_posture"][number]) {
  const blockedReason = getProviderBlockedReason(provider);
  if (!blockedReason) {
    return null;
  }
  if (provider.governed_handoff_ready) {
    return "Keep governed handoff active for this lane, then retry the direct path after validation passes.";
  }
  if (blockedReason === "ccr_config_missing" || blockedReason === "path_parity_partial") {
    return "Restore DEV parity first, then retry the blocked direct provider from subscription control.";
  }
  return "Restore the blocked direct lane, then retry the next provider execution request.";
}

export function MissionControl() {
  const cockpitQuery = useQuery({
    queryKey: queryKeys.cockpit,
    queryFn: getCockpit,
    ...liveQueryOptions(LIVE_REFRESH_INTERVALS.overview),
  });

  const snapshot = cockpitQuery.data;

  if (cockpitQuery.isError && !snapshot) {
    return (
      <div className="space-y-6">
        <PageHeader
          eyebrow="Operations"
          title="Command Center"
          description="The operator cockpit failed to load."
        />
        <ErrorPanel
          description={
            cockpitQuery.error instanceof Error
              ? cockpitQuery.error.message
              : "Failed to load mission-control state."
          }
        />
      </div>
    );
  }

  const loading = !snapshot;
  const activeRuns = snapshot?.run_ledger.active_count ?? 0;
  const pendingApprovals = snapshot?.run_ledger.pending_approvals ?? 0;
  const constrainedProviders = snapshot?.autonomy_economy.constrained_count ?? 0;
  const interventionCount = snapshot?.intervention_queue.count ?? 0;
  const releaseTier = snapshot?.autonomy_economy.release_tier ?? "unknown";

  return (
    <div className="space-y-8">
      <PageHeader
        eyebrow="Operations"
        title="Command Center"
        description="Mission control for live autonomous runs, provider posture, blocked work, and governed operator controls."
        actions={
          <>
            {snapshot ? (
              <LiveBadge
                updatedAt={snapshot.generated_at}
                intervalMs={LIVE_REFRESH_INTERVALS.overview}
              />
            ) : null}
            <Button asChild variant="outline">
              <Link href="/tasks">Open tasks</Link>
            </Button>
            <Button asChild variant="outline">
              <Link href="/review">Open review</Link>
            </Button>
            <Button asChild>
              <Link href="/agents">Open agents</Link>
            </Button>
          </>
        }
      >
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-5">
          <StatCard
            label="Active runs"
            value={loading ? "--" : `${activeRuns}`}
            detail={
              loading
                ? "Loading live run ledger."
                : `${snapshot?.run_ledger.runs.length ?? 0} recent governed runs visible.`
            }
            tone={activeRuns > 0 ? "success" : "default"}
            icon={<Activity className="h-5 w-5" />}
          />
          <StatCard
            label="Attention lane"
            value={loading ? "--" : `${interventionCount}`}
            detail={loading ? "Loading operator queue." : "Blocked or degraded items needing intervention."}
            tone={toneForStat(interventionCount)}
            icon={<AlertTriangle className="h-5 w-5" />}
          />
          <StatCard
            label="Pending approvals"
            value={loading ? "--" : `${pendingApprovals}`}
            detail={loading ? "Loading approval posture." : "Runs or tasks waiting on operator sign-off."}
            tone={toneForStat(pendingApprovals)}
            icon={<ShieldAlert className="h-5 w-5" />}
          />
          <StatCard
            label="Constrained providers"
            value={loading ? "--" : `${constrainedProviders}`}
            detail={loading ? "Loading provider plane." : "Cloud or adapter lanes not fully ready."}
            tone={toneForStat(constrainedProviders)}
            icon={<Cloud className="h-5 w-5" />}
          />
          <StatCard
            label="Release tier"
            value={formatLabel(releaseTier)}
            detail={
              loading
                ? "Loading governor posture."
                : `Governor ${formatLabel(snapshot?.autonomy_economy.global_mode)} | ${formatLabel(
                    snapshot?.autonomy_economy.presence_label
                  )}`
            }
            tone="default"
            icon={<Sparkles className="h-5 w-5" />}
          />
        </div>
      </PageHeader>

      <ProviderLifecycleBoard snapshot={snapshot} />

      <div className="grid gap-4 xl:grid-cols-[1.1fr_0.9fr]">
        <ActiveRunsPreview snapshot={snapshot} />
        <AttentionLane snapshot={snapshot} />
      </div>

      <div className="grid gap-4 xl:grid-cols-[0.95fr_1.05fr]">
        <AgentBoard snapshot={snapshot} />
        <ProviderPlaneSummary snapshot={snapshot} />
      </div>

      <div className="grid gap-4 xl:grid-cols-[1fr_1fr]">
        <GovernorCard />
        <OperationsReadinessCard
          snapshot={snapshot?.operator_truth}
          sourceState={snapshot?.source_states.operator_truth}
        />
      </div>

      <div className="grid gap-4 xl:grid-cols-[1fr_1fr]">
        <ExecutionRunsCard />
        <SubscriptionControlCard />
      </div>

      <div className="grid gap-4 xl:grid-cols-[1fr_1fr]">
        <JudgePlaneCard />
        <SystemMapCard />
      </div>

      <Card className="surface-panel">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <Sparkles className="h-5 w-5 text-primary" />
            Unified stream
          </CardTitle>
          <CardDescription>
            Cross-route operator activity, alerts, and governed run events in one lightweight feed.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <UnifiedStream limit={8} />
        </CardContent>
      </Card>

      <ModelGovernanceCard />
    </div>
  );
}

