type LifecycleCountKind = "review" | "adoption" | "cleanup" | "retention" | "cost" | "adoption_problem";
type PrimaryLifecycleKind =
  | "queued"
  | "running"
  | "handoff_pending"
  | "review_pending"
  | "adopted"
  | "cancelled"
  | "expired";

function countPrimaryLifecycleState<T extends Record<string, unknown>>(records: T[], kind: PrimaryLifecycleKind) {
  return records.filter((record) => getPrimaryLifecycleState(record) === kind).length;
}

function countLifecycleState<T extends Record<string, unknown>>(records: T[], kind: LifecycleCountKind) {
  return records.filter((record) => {
    const reviewState = getLifecycleState(record, ["review_state", "review_status"]);
    const adoptionState = getLifecycleState(record, ["adoption_status"]);
    const cleanupState = getLifecycleState(record, ["cleanup_status"]);

    switch (kind) {
      case "review":
        return Boolean(reviewState && reviewState.includes("pending"));
      case "adoption":
        return Boolean(adoptionState && adoptionState.includes("pending"));
      case "cleanup":
        return Boolean(
          (cleanupState &&
            (cleanupState.includes("failed") ||
              cleanupState.includes("rejected") ||
              cleanupState.includes("abandoned") ||
              cleanupState.includes("expired") ||
              cleanupState.includes("blocked"))) ||
            normalizeString(record.cleanup_reason)
        );
      case "retention":
        return hasRetentionHold(record);
      case "cost":
        return getCostStateLabel(record.cost_state) === null || getCostStateLabel(record.cost_state) === "unavailable";
      case "adoption_problem":
        return Boolean(
          adoptionState &&
            (adoptionState.includes("failed") ||
              adoptionState.includes("rejected") ||
              adoptionState.includes("abandoned") ||
              adoptionState.includes("expired") ||
              adoptionState.includes("blocked"))
        );
      default:
        return false;
    }
  }).length;
}

function getPrimaryLifecycleState(record: Record<string, unknown>) {
  const phase = getLifecycleState(record, ["provider_execution_phase"]);
  const reviewState = getLifecycleState(record, ["review_state", "review_status"]);
  const adoptionState = getLifecycleState(record, ["adoption_status"]);
  const cleanupState = getLifecycleState(record, ["cleanup_status"]);
  const status = normalizeLifecycleValue(record.status);

  if (cleanupState === "retention_expired" || cleanupState === "expired" || cleanupState === "purged") {
    return "expired";
  }
  if (phase === "cancelled" || status === "cancelled") {
    return "cancelled";
  }
  if (phase === "adopted" || adoptionState === "adopted") {
    return "adopted";
  }
  if (phase === "review_pending" || reviewState === "review_pending") {
    return "review_pending";
  }
  if (phase === "handoff_pending" || status === "handoff_created") {
    return "handoff_pending";
  }
  if (phase === "running" || status === "running") {
    return "running";
  }
  if (phase === "queued" || status === "pending") {
    return "queued";
  }
  return null;
}

function getLifecycleState(record: Record<string, unknown>, fields: string[]) {
  for (const field of fields) {
    const value = normalizeString(record[field]);
    if (value) {
      return normalizeLifecycleValue(value);
    }
  }
  return null;
}

function getLifecycleLabel(value: unknown) {
  const normalized = normalizeLifecycleValue(value);
  return normalized || null;
}

function badgeVariantForLifecycle(state: string | null | undefined) {
  const normalized = normalizeLifecycleValue(state);
  if (
    normalized.includes("failed") ||
    normalized.includes("rejected") ||
    normalized.includes("expired") ||
    normalized.includes("abandoned")
  ) {
    return "destructive" as const;
  }

  if (
    normalized.includes("pending") ||
    normalized.includes("blocked") ||
    normalized.includes("waiting") ||
    normalized.includes("retention") ||
    normalized.includes("cleanup")
  ) {
    return "secondary" as const;
  }

  return "outline" as const;
}

function hasRetentionHold(record: Record<string, unknown>) {
  return Boolean(
    normalizeString(record.retained_until) ||
      record.worktree_retained === true ||
      record.artifact_retained === true
  );
}

function getCostStateLabel(value: unknown) {
  if (typeof value === "string") {
    const normalized = normalizeLifecycleValue(value);
    return normalized || null;
  }

  if (value && typeof value === "object") {
    const state = normalizeString((value as { state?: unknown }).state);
    if (state) {
      return normalizeLifecycleValue(state);
    }
  }

  return null;
}

function formatCostState(value: unknown) {
  if (typeof value === "string") {
    return formatLabel(value);
  }

  if (value && typeof value === "object") {
    const state = normalizeString((value as { state?: unknown }).state);
    const detail = normalizeString((value as { detail?: unknown }).detail);
    if (state && detail) {
      return `${formatLabel(state)} | ${compactText(detail, 16)}`;
    }
    if (state) {
      return formatLabel(state);
    }
  }

  return "unknown";
}

function normalizeString(value: unknown) {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : "";
}

function normalizeLifecycleValue(value: unknown) {
  return normalizeString(value).toLowerCase().replace(/\s+/g, "_");
}
